const pdfText  = $json.text || '';
const formData = $('1. Form — Upload Vendor Proposal PDF').first().json;

const submitter      = (formData['Your Name']  || '').trim();
const submitterEmail = (formData['Your Email'] || '').trim();
const notes          = (formData['Notes for Evaluator'] || '').trim();
const submittedAt    = new Date().toISOString().split('T')[0];

if (!pdfText || pdfText.trim().length < 50) {
  throw new Error(
    'PDF text extraction failed or PDF is too short. ' +
    'Make sure the PDF contains selectable text (not a scanned image).' +
    ' Scanned PDFs require OCR pre-processing.'
  );
}

let cleanText = pdfText
  .replace(/\n\s*\n\s*\n/g, '\n\n')
  .replace(/^\d+\s*$/gm, '')
  .replace(/[ \t]{3,}/g, '  ')
  .trim()
  .substring(0, 6000);

return [{
  json: {
    cleanText,
    submitter,
    submitterEmail,
    notes,
    submittedAt
  }
}];

