const raw  = $input.first().json.output || '';
const meta = $('3. Code — Clean PDF Text and Prep Context').first().json;

let proposal = {};
try {
  const cleaned = raw.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  proposal = JSON.parse(cleaned);
} catch (e) {
  proposal = {
    vendor_name:       'Unknown Vendor',
    category:          'Unknown',
    summary:           'AI evaluation failed to parse. Raw output: ' + raw.substring(0, 200),
    key_points:        [],
    risks_or_concerns: ['AI evaluation output could not be parsed — manual review required']
  };
}

const risks     = Array.isArray(proposal.risks_or_concerns) ? proposal.risks_or_concerns : [];
const keyPoints = Array.isArray(proposal.key_points) ? proposal.key_points : [];
const riskFlagged = risks.length > 0;

const risksStr     = risks.length     > 0 ? risks.map((r, i) => (i+1) + '. ' + r).join('\n') : 'None identified';
const keyPointsStr = keyPoints.length > 0 ? keyPoints.map((k, i) => (i+1) + '. ' + k).join('\n') : 'None extracted';

return [{
  json: {
    vendorName:     proposal.vendor_name || 'Unknown Vendor',
    category:       proposal.category    || 'Unknown',
    summary:        proposal.summary     || '',
    keyPoints,
    risks,
    keyPointsStr,
    risksStr,
    riskFlagged,
    riskCount:      risks.length,
    decision:       riskFlagged ? 'REVIEW NEEDED' : 'APPROVED',
    submitter:      meta.submitter,
    submitterEmail: meta.submitterEmail,
    notes:          meta.notes,
    submittedAt:    meta.submittedAt
  }
}];
